// === Filtre + construction de la reponse (V3 OpenAI) ===
// Objectif :
// - ignorer les events Chatwoot parasites
// - ne garder que les vrais messages entrants
// - preparer le contexte minimal pour OpenAI puis Chatwoot

const item = $input.first()?.json ?? {};
const body = item.body ?? item;

// 1. On ne traite QUE les nouveaux messages.
if (body.event !== 'message_created') {
  return [];
}

// 2. On ignore les messages sortants (sinon le bot se repond a lui-meme).
const isIncoming = body.message_type === 'incoming' || body.message_type === 0;
if (!isIncoming) {
  return [];
}

// 3. Il nous faut une conversation pour pouvoir repondre.
const conversationId = body.conversation?.id;
if (!conversationId) {
  return [];
}

// 4. Il nous faut du texte non vide.
const content = (body.content ?? '').toString().trim();
if (!content) {
  return [];
}

const senderName = (body.sender?.name ?? 'prospect').toString().trim();

const systemPrompt = [
  'Tu es l\'assistant commercial de TransferAI Africa.',
  'Tu reponds exclusivement en francais, de facon claire, courte et professionnelle.',
  'Tu accueilles chaleureusement le prospect, reformules son besoin si utile, puis poses au maximum 3 questions de qualification.',
  'Tu aides surtout les organisations en Afrique a avancer sur la formation IA, la veille strategique et l\'automatisation.',
  'Si le besoin parait serieux et B2B, tu peux proposer une demo ou un echange avec l\'equipe.',
  'Ne promets jamais un prix, un delai ou un resultat non confirme.',
  'Reste concret, poli et utile.'
].join(' ');

const userPrompt = [
  `Nom du contact: ${senderName}`,
  `Message du prospect: ${content}`,
  'Reponds comme un conseiller TransferAI Africa et aide a qualifier le besoin.'
].join('\n');

return [
  {
    json: {
      conversation_id: conversationId,
      incoming_text: content,
      sender_name: senderName,
      system_prompt: systemPrompt,
      user_prompt: userPrompt,
      fallback_reply: 'Bonjour et merci pour votre message. Pour bien vous orienter, pouvez-vous me preciser le nom de votre entreprise, votre secteur d\'activite et votre besoin principal ?'
    }
  }
];

// === Normalisation de la reponse OpenAI ===
// Si OpenAI echoue ou renvoie vide, on garde le fallback statique.

const item = $input.first()?.json ?? {};
const aiText = item.choices?.[0]?.message?.content?.toString().trim();
const replyText = aiText || item.fallback_reply || 'Bonjour et merci pour votre message. Pour bien vous orienter, pouvez-vous me preciser le nom de votre entreprise, votre secteur d\'activite et votre besoin principal ?';

return [
  {
    json: {
      conversation_id: item.conversation_id,
      incoming_text: item.incoming_text,
      reply_text: replyText,
      used_fallback: !aiText
    }
  }
];
